const config = $('Fetch Bot Config').item.json;
const meta = $('Get Facebook Message').item.json.body;

if (!meta?.entry?.[0]?.messaging?.[0]) return [];

const messaging = meta.entry[0].messaging[0];
const senderId = messaging.sender.id;

// Ignore echo messages
if (messaging.message?.is_echo) return [];

// Fetch User Profile from Meta Graph API using fetch
let userName = 'Customer';
let profilePhoto = null;
try {
  const pageToken = config.pageToken;
  const profileRes = await fetch(`https://graph.facebook.com/v20.0/${senderId}?fields=first_name,last_name,profile_pic&access_token=${pageToken}`);
  const profileData = await profileRes.json();
  if (profileData) {
    if (profileData.first_name) {
      userName = `${profileData.first_name} ${profileData.last_name || ''}`.trim();
    }
    if (profileData.profile_pic) {
      profilePhoto = profileData.profile_pic;
    }
  }
} catch (e) {
  // Safe fallback
}

// Detect input type
const attachmentType = messaging.message?.attachments?.[0]?.type;
let messageText = '';
let messageType = 'text';

if (!attachmentType && messaging.message?.text) {
  messageText = messaging.message.text;
  messageType = 'text';
} else if (attachmentType === 'image') {
  messageText = $json.imageDescription || 'User sent an image.';
  messageType = 'image';
} else if (attachmentType === 'audio') {
  messageText = $json.text || $json.transcription || 'User sent a voice message.';
  messageType = 'audio';
} else {
  return [];
}

// Append order handling instruction to system prompt
const orderInstruction = `\n\n---\nWhen a customer confirms their order by providing name, phone, and address, respond ONLY with this JSON (no other text):\n{"action":"create_order","recipient_name":"<name>","recipient_phone":"<phone>","recipient_address":"<address>","cod_amount":"<total BDT>","product_name":"<product name>"}\nFor all other conversations, respond normally.`;

// Language Rules
const languageRules = `\n\n---\nLANGUAGE RULES:\n1. Detect the user's language (English, Bengali, or Banglish/Romanized Bengali).\n2. ALWAYS reply in the exact same language and script that the user used. If they ask in Bangla, reply in Bangla. If they ask in Banglish, reply in Bangla or natural Banglish.\n3. You are fully multilingual. NEVER say "I can only speak English" or refuse to assist in Bengali.\n4. Keep product names (e.g., "Olive Green Casual"), sizes, and Product IDs in their original English/Roman script as written in the sheet, even when replying in Bengali.\n\nTONE & FORMATTING RULES:\n1. Speak in a friendly, natural, helpful, and human-like tone. Avoid sounding rigid or robotic.\n2. DO NOT greet the customer as "Sir/Madam" or "Dear Customer" in every message. Only greet them in the very first message of the conversation. In subsequent messages, get straight to the point politely.\n3. Organize information beautifully. Use paragraph spacing, line breaks, bullet points, and appropriate emojis (e.g., 🏷️ for price, 📦 for stock, 🚚 for shipping) to make the text clean, readable, and engaging.`;

// Dynamic tool selection rules
const hasSheet = !!config.productSheetId;
const isEcommerce = config.chatbotMode === 'ecommerce';
const toolRules = isEcommerce && hasSheet
  ? `\n\n---\nTOOL RULES:\n1. Product-specific queries (including name, price, stock, size, color, quality, fabric, material, purity, ingredients, authenticity, benefits, description, etc.) - ALWAYS call the 'Get Product form Sheet' tool FIRST. Do not try to guess or answer from your own knowledge.\n2. General questions (FAQ, company info, delivery policies) - use 'knowledge_base' tool.\n3. If the user asks about any product attributes, characteristics, or specific details in English, Bangla, or Banglish (e.g. 'quality kemon', 'original naki', 'dam koto', 'size ache?'), translate the context and look up the sheet.`
  : (hasSheet
      ? `\n\n---\nTOOL RULES:\n1. Product-specific queries (name, price, stock) - use 'Get Product form Sheet' tool.\n2. General questions - use 'knowledge_base' tool.`
      : `\n\n---\nTOOL RULES:\n- Use 'knowledge_base' tool to find relevant info before answering.`);

return [{
  json: {
    ...config,
    senderId,
    sessionId: `fb_${senderId}`,
    messageText,
    messageType,
    userName,
    profilePhoto,
    systemPrompt: config.systemPrompt + orderInstruction + languageRules + toolRules
  }
}];

const raw = $('Anylize').item.json.output ?? '{}';

let parsed;

try {
  parsed = typeof raw === 'string' ? JSON.parse(raw) : raw;
} catch (error) {
  parsed = {
    sentiment: null,
    topic: null,
    rawOutput: raw,
  };
}

return [
  {
    json: {
      sentiment: parsed.sentiment ?? null,
      topic: parsed.topic ?? null,
      rawAnalysis: parsed,
    },
  },
];

const output = $('Brain').item.json.output ?? '';
let isOrder = false;
let orderData = null;
try {
  const parsed = JSON.parse(output.trim());
  if (parsed.action === 'create_order') {
    isOrder = true;
    orderData = parsed;
  }
} catch {}
return [{ json: { isOrder, orderData, normalResponse: output } }];

