parameters.jsCode:
const cfg = $('Fetch Comment Config').item.json;
const body = $('Get Facebook Message').item.json.body;

// Parse commentReply config from DB
let crCfg = {};
try {
  crCfg = typeof cfg.commentReplyConfig === 'string'
    ? JSON.parse(cfg.commentReplyConfig)
    : (cfg.commentReplyConfig || {});
} catch(e) {}

// Exit if disabled or no quota
if (!crCfg.enabled) return [];
if ((cfg.messagesRemaining || 0) <= 0) return [];

const change = body.entry?.[0]?.changes?.[0]?.value;
if (!change || change.item !== 'comment' || change.verb !== 'add') return [];

const commentId = change.comment_id;
const fromId = change.from?.id;
const fromName = change.from?.name || 'Customer';
const commentText = (change.message || '').trim();
const pageId = cfg.pageId;

// Skip bot's own comments (prevent infinite loop)
if (fromId === pageId) return [];
if (!commentText) return [];

return [{
  json: {
    ...cfg,
    commentId,
    fromId,
    fromName,
    commentText,
    sessionId: `fb_comment_${fromId}`,
    mode: crCfg.mode || 'ai',
    fixedMessage: crCfg.fixedMessage || '',
    sendPrivateDM: crCfg.sendPrivateDM || false
  }
}];

