INSERT INTO "ChatSession" ("id", "chatbotId", "sessionId", "platform", "guestName", "isActive", "createdAt", "updatedAt")
VALUES (gen_random_uuid()::text, '{{ $('Extract Comment Data').item.json.chatbotId }}', '{{ $('Extract Comment Data').item.json.sessionId }}', 'facebook_comment', '{{ $('Extract Comment Data').item.json.fromName }}', true, NOW(), NOW())
ON CONFLICT ("chatbotId", "sessionId") DO UPDATE SET "updatedAt" = NOW();

INSERT INTO "ChatMessage" ("id", "chatbotId", "userId", "sessionId", "role", "content", "timestamp")
VALUES
  (gen_random_uuid()::text, '{{ $('Extract Comment Data').item.json.chatbotId }}', '{{ $('Extract Comment Data').item.json.userId }}', '{{ $('Extract Comment Data').item.json.sessionId }}', 'user', '{{ $('Extract Comment Data').item.json.commentText }}', NOW() - INTERVAL '1 second'),
  (gen_random_uuid()::text, '{{ $('Extract Comment Data').item.json.chatbotId }}', '{{ $('Extract Comment Data').item.json.userId }}', '{{ $('Extract Comment Data').item.json.sessionId }}', 'assistant', '{{ $json.finalReply }}', NOW());

UPDATE "User" SET "messagesUsedThisCycle" = "messagesUsedThisCycle" + 1 WHERE "userId" = '{{ $('Extract Comment Data').item.json.userId }}';
